<script setup lang="ts">import { computed, reactive, ref } from 'vue'; import type { CategoryNode, ItemInput } from '../../catalog/catalogModels'; const props=defineProps<{categories:CategoryNode[];initial?:Partial<ItemInput>;pending?:boolean}>(); const emit=defineEmits<{save:[ItemInput]}>(); const error=ref(''); const form=reactive({name:props.initial?.name??'',categoryId:props.initial?.categoryId??'',defaultUnit:props.initial?.defaultUnit??'个',brand:props.initial?.brand??null,model:props.initial?.model??null,specification:props.initial?.specification??null,defaultShelfLifeValue:props.initial?.defaultShelfLifeValue??null,defaultShelfLifeUnit:props.initial?.defaultShelfLifeUnit??null,customAttributes:{...(props.initial?.customAttributes??{})} as Record<string,unknown>,barcodes:[...(props.initial?.barcodes??[])] as string[],tags:[...(props.initial?.tags??[])] as string[],version:props.initial?.version}); const category=computed(()=>props.categories.find(c=>c.id===form.categoryId)); const barcode=ref(''); function addBarcode(){const raw=barcode.value.trim();if(!raw)return;if(form.barcodes.some(v=>v.toUpperCase()===raw.toUpperCase())){error.value='条码不能重复';return}form.barcodes.push(raw);barcode.value=''} function save(){if(!form.name.trim()||!form.categoryId){error.value='请填写名称和分类';return}emit('save',{...form} as ItemInput)}</script>
<template><el-card class="catalog-form" shadow="never"><el-form label-position="top" @submit.prevent="save"><el-alert v-if="error" :title="error" type="error" show-icon :closable="false" /><el-row :gutter="16"><el-col :xs="24" :sm="12"><el-form-item label="物品名称"><el-input v-model="form.name" required /></el-form-item></el-col><el-col :xs="24" :sm="12"><el-form-item label="分类"><el-select v-model="form.categoryId" required filterable><el-option v-for="categoryOption in categories" :key="categoryOption.id" :label="categoryOption.name" :value="categoryOption.id" /></el-select></el-form-item></el-col><el-col :xs="24" :sm="12"><el-form-item label="默认单位"><el-input v-model="form.defaultUnit" /></el-form-item></el-col><el-col v-for="field in category?.attributeSchema" :key="field.key" :xs="24" :sm="12"><el-form-item :label="field.label"><el-input v-if="field.type==='TEXT'||field.type==='DATE'||field.type==='NUMBER'" :model-value="String(form.customAttributes[field.key] ?? '')" :type="field.type==='NUMBER'?'number':field.type==='DATE'?'date':'text'" @update:model-value="form.customAttributes[field.key] = $event"/><el-switch v-else-if="field.type==='BOOLEAN'" :model-value="Boolean(form.customAttributes[field.key])" @update:model-value="form.customAttributes[field.key] = $event"/><el-select v-else :model-value="String(form.customAttributes[field.key] ?? '')" @update:model-value="form.customAttributes[field.key] = $event"><el-option v-for="option in field.options" :key="option" :label="option" :value="option" /></el-select></el-form-item></el-col><el-col :span="24"><el-form-item label="添加条码"><el-input v-model="barcode" @keydown.enter.prevent="addBarcode"><template #append><el-button @click="addBarcode">添加</el-button></template></el-input></el-form-item><el-space wrap><el-tag v-for="code in form.barcodes" :key="code">{{ code }}</el-tag></el-space></el-col></el-row><el-button native-type="submit" type="primary" :loading="pending">保存物品</el-button></el-form></el-card></template>
